}) {
  // previewState is used by the Figma matrix only. Application code uses
  // variant, size and the native disabled prop as it would in production.
  const state = previewState || (disabled ? "disabled" : "default");
  const isDisabled = disabled || state === "disabled";
  const icons = previewIcons || (Array.isArray(icon) ? icon : icon ? [icon] : []);
  const content = previewContent || [
    ...icons.map((_, index) => ({ type: "icon", index })),
    { type: "label" },
  ];
  return (
    <button
      {...buttonProps}
      type={type}
      className={["caba-button", "caba-button--" + variant, "caba-button--" + state, "caba-button--" + size, className].filter(Boolean).join(" ")}
      disabled={isDisabled}
      style={style}
      onClick={onClick}
    >
      {content.map((item, contentIndex) => item.type === "icon" ? (
        <span key={"icon-" + contentIndex} className={"caba-button__icon caba-button__icon--" + item.index} aria-hidden="true">{icons[item.index]?.glyph || icons[item.index] || ""}</span>
      ) : (
        <span key={"label-" + contentIndex} className="caba-button__label">{children}</span>
      ))}
    </button>
  );
}

