}

.caba-spark__figma-0-icon-spark {
  position: absolute;
  box-sizing: border-box;
  width: 16px;
  height: 16px;
  border: 0;
  opacity: 1;
  display: block;
}

.caba-spark__figma-1-spark {
  position: absolute;
  box-sizing: border-box;
  left: 3px;
  top: -2px;
  width: 10px;
  height: 17px;
  border: 0;
  opacity: 1;
  display: block;
  margin: 0;
  white-space: pre-wrap;
  overflow-wrap: normal;
  color: var(--semantic-color-icon-default);
  font-family: var(--core-font-family-sans);
  font-size: 14px;
  font-weight: 700;
  line-height: 17px;
  letter-spacing: 0;
  text-align: left;
}

`;


const FIGMA_LAYOUT = [
  {
    "index": 0,
    "axes": {},
    "x": 0,
    "y": 0
  }
];
const DEFAULT_AXES = {};

function SparkFigmaLayer({ figmaIndex = 0, previewStyle, className = "", rootProps = {} }) {
  switch (figmaIndex) {
    case 0: return (
      <div {...rootProps} className={["caba-spark", "caba-spark__figma-0-icon-spark", className].filter(Boolean).join(" ")} style={previewStyle}>
      <span className="caba-spark__figma-1-spark">{"+"}</span>
      </div>
    );
    default: return null;
  }
}

function Spark({
  axisValues = {},
  previewStyle
} = {}) {
  const activeAxes = { ...DEFAULT_AXES, ...axisValues,  };
  const selected = FIGMA_LAYOUT.find((item) => Object.entries(item.axes || {}).every(([axis, value]) => activeAxes[axis] === value)) || FIGMA_LAYOUT[0];
  return <SparkFigmaLayer figmaIndex={selected.index} previewStyle={previewStyle}  />;
}

const Demo = () => (
  <div className="caba-figma-set--spark">
    <style>{css}</style>
    {FIGMA_LAYOUT.map((item) => (
      <Spark
        key={item.index}
        axisValues={item.axes}

        previewStyle={{ left: item.x, top: item.y }}
      />
    ))}
  </div>
);

render(<Demo />);
